import sys
from typing import List

class Solution:
    def solve(self, graph: List[List[int]]) -> List[List[int]]:
        n = len(graph)
        dist = [[float('inf')] * n for _ in range(n)]
        for i in range(n):
            for j in range(n):
                dist[i][j] = graph[i][j]
        for k in range(n):
            for i in range(n):
                for j in range(n):
                    dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j])
        return dist

if __name__ == '__main__':
    it = iter(sys.stdin.read().splitlines())
    try:
        n = int(next(it))
        graph = [list(map(lambda x: int(x) if x != 'INF' else float('inf'), next(it).split())) for _ in range(n)]
    except StopIteration:
        sys.exit(0)
    sol = Solution()
    ans = sol.solve(graph)
    for row in ans:
        print(' '.join(map(lambda x: str(x) if x != float('inf') else 'INF', row)))

