#include <numeric>
#include <bits/stdc++.h>
using namespace std;

class Solution {
public:
    vector<vector<int>> solve(vector<vector<int>>& graph) {
        int n = graph.size();
        vector<vector<int>> dist = graph;
        for (int k = 0; k < n; k++) {
            for (int i = 0; i < n; i++) {
                for (int j = 0; j < n; j++) {
                    if (dist[i][k] != INT_MAX && dist[k][j] != INT_MAX) {
                        dist[i][j] = min(dist[i][j], dist[i][k] + dist[k][j]);
                    }
                }
            }
        }
        return dist;
    }
};

int main() {
    ios::sync_with_stdio(false);
    cin.tie(nullptr);
    int n;
    cin >> n;
    vector<vector<int>> graph(n, vector<int>(n));
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            string s;
            cin >> s;
            if (s == "INF") {
                graph[i][j] = INT_MAX;
            } else {
                graph[i][j] = stoi(s);
            }
        }
    }
    Solution sol;
    vector<vector<int>> ans = sol.solve(graph);
    for (int i = 0; i < n; i++) {
        for (int j = 0; j < n; j++) {
            if (ans[i][j] == INT_MAX) {
                cout << "INF";
            } else {
                cout << ans[i][j];
            }
            cout << (j == n - 1 ? "" : " ");
        }
        cout << "\n";
    }
    return 0;
}
